using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;/// <summary>/// Authorization test: Try to create EHR without authentication/// Expected: 401 Unauthorized/// </summary>public class EhrServiceTests_CreateEhrRecord_WithoutAuthentication_ShouldReturnUnauthorized : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task CreateEhrRecord_WithoutAuthentication_ShouldReturnUnauthorized()    {        // Don't authenticate, send request directly        var request = new         {             patientId = TestSeedData.PatientUserId,             orgId = TestSeedData.HospitalAOrgId,             encounterId = Guid.NewGuid(),             data = new             {                 doctorId = TestSeedData.DoctorUserId,                 diagnosis = "Test",                 treatment = "Test",                 notes = "Test"             }         };        // Create unauthenticated client        using var unauthenticatedClient = new HttpClient { BaseAddress = EhrClient.BaseAddress };                var response = await PostAsJsonWithRetryAsync(unauthenticatedClient, ApiEndpoints.Ehr.CreateRecord, request);        Assert.Equal(HttpStatusCode.Unauthorized, response.StatusCode);    }}